import path from 'path';
import micromatch from 'micromatch';

/**
 * 向上查找，直到找到名为 workspace 的目录
 * @param startPath 起始路径
 * @returns workspace 目录的路径，如果找不到则返回当前工作目录的上一级
 */
export const findWorkspaceRoot = (startPath: string): string => {
  let currentPath = path.resolve(startPath);
  const {root} = path.parse(currentPath);

  while (currentPath !== root) {
    const dirName = path.basename(currentPath);
    if (dirName === 'workspace') {
      return currentPath;
    }
    currentPath = path.dirname(currentPath);
  }

  // 如果找不到 workspace，返回当前工作目录的上一级作为后备
  return path.resolve(process.cwd(), '..');
};

const normalizePatterns = (patterns: string | string[]): string[] => {
  return Array.isArray(patterns) ? patterns : [patterns];
};

export const isIncludedFile = (file: string, include: string | string[], exclude: string | string[] = []): boolean => {
  const includePatterns = normalizePatterns(include);
  const excludePatterns = normalizePatterns(exclude);

  const matched = includePatterns.some((pattern) => micromatch.isMatch(file, pattern));
  const excluded = excludePatterns.length > 0 && excludePatterns.some((pattern) => micromatch.isMatch(file, pattern));

  return matched && !excluded;
};
